mapper.select:
SELECT 전담자번호 memberNo, 지점 branch, 이름 memberName, 아이디 userId, 권한 role, 관리자권한 isAdmin, 등록일 regDate, 이메일 email, 전화번호 phoneNumber, 아이디사용여부 useStatus, 입사일 hireDate, 최종발령일 lastAssignDate, 근속기간구분 continuousPeriod, 조회순서 viewOrder, 실적작성여부 performanceWrite, 일일업무일지발급여부 dailyReportIssue, 배정가중치 assignWeight FROM J_참여자관리_로그인정보 WHERE 1=1
AND 지점 = #{searchBranch}
AND 이름 LIKE '%' + #{searchName} + '%'
AND 아이디 LIKE '%' + #{searchUserId} + '%'
AND 권한 = #{searchRole}
ORDER BY 조회순서 ASC, 전담자번호 ASC

mapper.insert:
INSERT INTO J_직원 (아이디, 이름, 이메일, 전화번호, 최초입사일, 현재재직상태, 등록일, 수정일)
VALUES (#{userId}, #{memberName}, #{email}, #{phoneNumber}, #{hireDate}, N'재직', GETDATE(), GETDATE());

INSERT INTO J_직원_계정 (아이디, 비밀번호, 계정상태)
VALUES (#{userId}, #{password}, ISNULL(#{useStatus}, N'사용'));

INSERT INTO J_직원_재직 (아이디, 주부서코드, 지점명, 권한, 관리자권한, 최종발령일)
VALUES (#{userId},
        (SELECT 부서코드 FROM J_부서 WHERE 지점명 = #{branch}),
        #{branch}, ISNULL(#{role}, N'상담'), #{isAdmin}, #{lastAssignDate});

INSERT INTO J_직원_부서배치 (직원아이디, 부서코드, 주부서여부, 시작일)
VALUES (#{userId},
        (SELECT 부서코드 FROM J_부서 WHERE 지점명 = #{branch}), 1, ISNULL(#{hireDate}, GETDATE()));

INSERT INTO J_직원_참여자관리_프로필 (직원아이디, 조회순서, 실적작성여부, 일일업무일지발급여부, 배정가중치)
VALUES (#{userId}, #{viewOrder}, #{performanceWrite}, #{dailyReportIssue}, #{assignWeight});


INSERT INTO J_직원_사이트접속 (직원아이디, 사이트코드, 부서코드, 접속허용, 사이트내권한)
VALUES (#{userId}, N'COUNSEL', NULL, 1, NULL);



    INSERT INTO J_직원_재직기간 (직원아이디, 재직순번, 입사일)
    VALUES (#{userId}, 1, #{hireDate});

mapper.update:
DECLARE @아이디 nvarchar(20) = (SELECT 아이디 FROM J_직원 WHERE 직원번호 = #{memberNo});
UPDATE J_직원 SET 이름 = #{memberName}, 이메일 = #{email}, 전화번호 = #{phoneNumber}, 최초입사일 = #{hireDate}, 수정일 = GETDATE() WHERE 아이디 = @아이디;
UPDATE J_직원_계정 SET 계정상태 = #{useStatus} WHERE 아이디 = @아이디;
UPDATE J_직원_재직 SET 권한 = #{role}, 관리자권한 = #{isAdmin}, 최종발령일 = #{lastAssignDate}, 지점명 = #{branch}, 주부서코드 = (SELECT 부서코드 FROM J_부서 WHERE 지점명 = #{branch}), 수정일 = GETDATE() WHERE 아이디 = @아이디;
UPDATE J_직원_참여자관리_프로필 SET 조회순서 = #{viewOrder}, 실적작성여부 = #{performanceWrite}, 일일업무일지발급여부 = #{dailyReportIssue}, 배정가중치 = #{assignWeight} WHERE 직원아이디 = @아이디;
UPDATE J_직원_부서배치 SET 부서코드 = (SELECT 부서코드 FROM J_부서 WHERE 지점명 = #{branch}) WHERE 직원아이디 = @아이디 AND 종료일 IS NULL AND 주부서여부 = 1;

mapper.delete:
DECLARE @아이디 nvarchar(20) = (SELECT 아이디 FROM J_직원 WHERE 직원번호 = #{memberNo});

UPDATE J_직원
SET 현재재직상태 = N'퇴사', 수정일 = GETDATE()
WHERE 아이디 = @아이디;

UPDATE J_직원_재직기간
SET 퇴사일 = CAST(GETDATE() AS date)
WHERE 직원아이디 = @아이디 AND 퇴사일 IS NULL;

